sql:
SELECT SUM(calories_burned) AS total_calories_burned
FROM workouts
WHERE workout_id = 0;

external_knowledge:
; The query assumes that the 'popularity' of a workout is determined by the total number of likes it has received; 
; The 'latest comment date' refers to the most recent date a coach made a comment on a workout; 
; The 'sport like rank' represents the ranking of a workout within its sport based on the total likes it has received.
